import java.util.*;
import java.util.function.*;
public class Capture {
    public static void main(String[] args) {
        int threshold = 5;
        List<Integer> nums = List.of(1, 3, 7, 2, 9, 4);
        threshold = 10;                           // reassignment
        Predicate<Integer> above = n -> n > threshold;
        nums.stream().filter(above).forEach(System.out::println);
    }
}
